import streamlit as stimport plotly.express as pxfrom backend import get_dataimport sys# Add title, text input, slider, selectbox and subheader# st.set_page_config(layout="wide")st.title("Weather Forecast for The Next Days")place = st.text_input("Place")days = st.slider("forecast Days", min_value= 1, max_value=5, help="Select the number of forecasted days")option = st.selectbox("Select data to view", ["Temperature", "Sky"], filter_mode=None)st.subheader(f"{option} for the next {days} days in {place}")if place:    try:        # Get the temperature / sky data        filtered_data = get_data(place, days)        print(filtered_data)    except Exception as e:        st.error("Please enter a valid place name.")        sys.exit()    if option == "Temperature":        # list comprehension to extract temperature data from the filtered data        temperatures = [dict['main']['temp'] for dict in filtered_data]        # convert temperatures from Kelvin to Celsius        temperatures = [temp - 273.15 for temp in temperatures]        dates = [dict["dt_txt"] for dict in filtered_data]        # Create a temperature plot        figure = px.line(x=dates, y=temperatures, labels={"x": "Date", "y": "Temperature (°C)"})        st.plotly_chart(figure)    if option == "Sky":        images = {"Clear": "images/clear.png", "Clouds": "images/cloud.png", "Rain": "images/rain.png", "Snow": "images/snow.png"}        sky_conditions = [dict["weather"][0]["main"] for dict in filtered_data]        dates = [dict["dt_txt"] for dict in filtered_data]        # Translating the data: Use list comprehension to translate the sky condition data into a list of image paths        image_paths = [images[condition] for condition in sky_conditions]        print()        st.image(image_paths, width=115, caption=dates)